import React from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import { Typography } from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';

// Components
import Layout from '../components/Layout';
import SEO from '../components/SEO';

const useStyles = makeStyles((theme) => ({
    fortyTwoWrapper: {
        margin: '10px 0',
    },
    videoWrapper: {
        position: 'relative',
        paddingBottom: '56.25%', /* 16:9 */
        height: 0,
        overflow: 'hidden',
    },
    videoWrapperIframe: {
        position: 'absolute',
        top: 0,
        left: 0,
        width: '100%',
        height: '100%',
    },
}));

const FortyTwo = ({ location }) => {
    const classes = useStyles();
    const intl = useIntl();

    return (
        <Layout hideTopbar>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                robots="noindex, nofollow"
                title={intl.formatMessage({ id: 'forty_two_page.title' })}
            />
            <div className={classes.fortyTwoWrapper}>
                <div className={classes.videoWrapper}>
                    <iframe
                        className={classes.videoWrapperIframe}
                        title="The SpongeBob Movie: Sponge Out of Water (2015) - Dolphin Rap Battle Scene"
                        // width="560"
                        // height="315"
                        src="https://www.youtube.com/embed/5TG1Wh04D1g?autoplay=1"
                        frameBorder="0"
                        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                        allowFullScreen
                    />
                </div>
                <br />
                <Typography
                    color="textPrimary"
                >
                    {intl.formatMessage({ id: 'forty_two_page.description' })}
                </Typography>
            </div>
        </Layout>
    );
};

export default FortyTwo;
